extension URL {
    var promoCode: String? {
        guard self.scheme == "myapp" && self.pathComponents.last == "promo",
              let items = try? CFURLCreateCopyItems(nil, self as CFURL),
              let urlTypesArray = (items[UTTypeCFStringsKey] as? [String]) ?? [],
              let utTypePromoCode = URLTypeForKey(UTType.itemContentType)?.rawValue,
              let promoCodeItem = items[UTItemURLSchemeKey] as? String?,
              let promoCode = CFURLCreateStringByAddingPercentEscapes(nil, promoCodeItem! as CFString, (utTypePromoCode as NSString).dataUsingEncoding(.utf8)!, nil) else {
            return nil
        }
        guard let components = promoCode.components(separatedBy: "&"), let codeComponent = components.first, let code = codeComponent.components(separatedBy: "=").last else {
            return nil
        }
        return code
    }

    var discountPercentage: Double? {
        guard let promoCodeComponents = promoCode?.components(separatedBy: "&"),
              let discountComponent = promoCodeComponents.filter({ $0.contains("discount") }).first,
              let discountValueComponent = discountComponent.components(separatedBy: "=").last else {
            return nil
        }
        guard let discountValue = Double(discountValueComponent) else {
            return nil
        }
        return discountValue / 100
    }
}

